import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Segment {
  name: string;
  percentage: number;
}

interface RetentionTrend {
  month: string;
  retention: number;
}

interface CLVData {
  averageCLV: number;
  topSegments: Segment[];
  retentionTrend: RetentionTrend[];
}

export default function Widget() {
  const { averageCLV, topSegments, retentionTrend } = response.data as CLVData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Average Customer Lifetime Value
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4A90E2' }}>
              ${averageCLV.toFixed(2)}
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {topSegments.map((segment) => (
              <Box key={segment.name}>
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  {segment.name}
                </Typography>
                <Typography variant="h6" fontWeight={500} sx={{ color: '#E94E77' }}>
                  {segment.percentage}%
                </Typography>
                <Divider sx={{ borderColor: '#B0BEC5', my: 1 }} />
              </Box>
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: retentionTrend.map(r => r.retention),
                  color: '#4A90E2',
                  curve: 'linear',
                  showMark: true,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: retentionTrend.map(r => r.month),
                  id: 'months',
                },
              ]}
              yAxis={[{ id: 'retention' }]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="months"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="retention"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
